module top_module(
    input [3:0] a,
    input [3:0] b,
    input not_sel,
    output reg [3:0] out
);always @(*) begin
        out[0] = a[0] ^ (not_sel & b[0]);
        out[1] = a[1] ^ (not_sel & b[1]);
        out[2] = a[2] ^ (not_sel & b[2]);
        out[3] = a[3] ^ (not_sel & b[3]);
    end

endmodule
